Create a new test file to verify the `/session` route loader behavior — redirecting to cached sessions, generating UUIDs for empty cache, and preserving the `?dir=` param.

## Implementation

**File:** `apps/client/src/__tests__/router.test.ts` (new file)

This test file tests the loader function by extracting it from the route definition or testing it indirectly. Since TanStack Router loaders are functions that receive a context object, the cleanest approach is to test the loader logic directly.

However, the loader is defined inline in `createRoute()`. To test it, we need to either:
1. Extract the loader into a named export, OR
2. Test the router behavior end-to-end

The recommended approach is to extract the loader logic into a testable function and test it directly.

### Step 1: Extract the loader into a named function in `router.tsx`

In `apps/client/src/router.tsx`, extract the loader:

```typescript
import type { Session } from '@dorkos/shared/types';

/**
 * Loader for the /session route. Redirects to the most recent cached session
 * or generates a speculative UUID when no session param is provided.
 *
 * @internal Exported for testing only.
 */
export function sessionRouteLoader({
  context: { queryClient },
  location,
}: {
  context: { queryClient: QueryClient };
  location: { searchStr: string };
}) {
  const params = new URLSearchParams(location.searchStr);
  const session = params.get('session');

  // Session already specified — nothing to do
  if (session) return;

  // Read cached session list (may be stale or empty on first load)
  const dir = params.get('dir') ?? undefined;
  const sessions = queryClient.getQueryData<Session[]>(['sessions', dir ?? null]);

  if (sessions && sessions.length > 0) {
    // Auto-select most recent session
    throw redirect({
      to: '/session',
      search: {
        session: sessions[0].id,
        dir,
      },
      replace: true,
    });
  }

  // No sessions cached — generate a fresh UUID for a new session
  throw redirect({
    to: '/session',
    search: {
      session: crypto.randomUUID(),
      dir,
    },
    replace: true,
  });
}
```

Then use it in the route definition:
```typescript
const sessionRoute = createRoute({
  getParentRoute: () => appShellRoute,
  path: '/session',
  validateSearch: zodValidator(sessionSearchSchema),
  component: SessionPage,
  loader: sessionRouteLoader,
});
```

### Step 2: Create the test file

```typescript
/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { QueryClient } from '@tanstack/react-query';
import { sessionRouteLoader } from '../router';
import type { Session } from '@dorkos/shared/types';

// TanStack Router's redirect() throws an object with specific shape.
// We catch and inspect it to verify redirect behavior.
interface RedirectResult {
  to: string;
  search: Record<string, string | undefined>;
  replace: boolean;
}

function callLoader(queryClient: QueryClient, searchStr: string) {
  return sessionRouteLoader({
    context: { queryClient },
    location: { searchStr },
  });
}

function makeSession(overrides: Partial<Session> = {}): Session {
  return {
    id: overrides.id ?? 'session-1',
    title: overrides.title ?? 'Test session',
    createdAt: overrides.createdAt ?? '2026-02-07T10:00:00Z',
    updatedAt: overrides.updatedAt ?? '2026-02-07T14:00:00Z',
    permissionMode: overrides.permissionMode ?? 'default',
    ...overrides,
  };
}

describe('sessionRouteLoader', () => {
  let queryClient: QueryClient;

  beforeEach(() => {
    queryClient = new QueryClient({
      defaultOptions: { queries: { retry: false } },
    });
  });

  it('does not redirect when ?session= param is present', () => {
    const result = callLoader(queryClient, '?session=abc-123');
    // Should return undefined (no redirect thrown)
    expect(result).toBeUndefined();
  });

  it('redirects to first cached session when cache has sessions and no ?session= param', () => {
    queryClient.setQueryData<Session[]>(['sessions', null], [
      makeSession({ id: 's1', title: 'Most recent' }),
      makeSession({ id: 's2', title: 'Older' }),
    ]);

    try {
      callLoader(queryClient, '');
      // Should not reach here — redirect throws
      expect.fail('Expected redirect to be thrown');
    } catch (thrown) {
      const redirectObj = thrown as RedirectResult;
      expect(redirectObj.to).toBe('/session');
      expect(redirectObj.search.session).toBe('s1');
      expect(redirectObj.replace).toBe(true);
    }
  });

  it('redirects to new UUID when cache is empty and no ?session= param', () => {
    // No sessions in cache
    try {
      callLoader(queryClient, '');
      expect.fail('Expected redirect to be thrown');
    } catch (thrown) {
      const redirectObj = thrown as RedirectResult;
      expect(redirectObj.to).toBe('/session');
      // Should be a UUID-format string
      expect(redirectObj.search.session).toMatch(
        /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i
      );
      expect(redirectObj.replace).toBe(true);
    }
  });

  it('preserves ?dir= param in redirect to cached session', () => {
    queryClient.setQueryData<Session[]>(['sessions', '/my/project'], [
      makeSession({ id: 's1' }),
    ]);

    try {
      callLoader(queryClient, '?dir=/my/project');
      expect.fail('Expected redirect to be thrown');
    } catch (thrown) {
      const redirectObj = thrown as RedirectResult;
      expect(redirectObj.search.session).toBe('s1');
      expect(redirectObj.search.dir).toBe('/my/project');
    }
  });

  it('preserves ?dir= param in redirect to new UUID', () => {
    // No sessions cached for this dir
    try {
      callLoader(queryClient, '?dir=/my/project');
      expect.fail('Expected redirect to be thrown');
    } catch (thrown) {
      const redirectObj = thrown as RedirectResult;
      expect(redirectObj.search.dir).toBe('/my/project');
      expect(redirectObj.search.session).toMatch(
        /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i
      );
    }
  });

  it('uses correct cache key with dir param', () => {
    // Sessions cached under dir key, NOT under null key
    queryClient.setQueryData<Session[]>(['sessions', '/my/project'], [
      makeSession({ id: 'dir-session' }),
    ]);
    // No sessions under null key

    try {
      callLoader(queryClient, '?dir=/my/project');
      expect.fail('Expected redirect to be thrown');
    } catch (thrown) {
      const redirectObj = thrown as RedirectResult;
      expect(redirectObj.search.session).toBe('dir-session');
    }
  });
});
```

Note: The TanStack Router `redirect()` function throws an object. The test catches these thrown objects and inspects their properties. The exact shape depends on the TanStack Router version, but it includes `to`, `search`, and `replace` properties. If the redirect throws a wrapper object, you may need to adjust the type assertion (e.g., check `thrown.redirect` or similar). Verify by logging the thrown value in the first failing test run.

